     1→// FreeLang v6: Virtual Machine
     2→
     3→import { Op, Value, Chunk } from "./compiler";
     4→import { getBuiltins } from "./stdlib/builtins";
     5→import { JumpTable, OffsetCalculator } from "./jump-table";
     6→import { MemoryAllocator } from "./memory-allocator";
     7→import { HeapManager, TYPE_ID } from "./heap-manager";
     8→import { UnsafeManager } from "./unsafe-manager";
     9→
    10→type BuiltinFn = (args: Value[], vm: VM) => Value;
    11→type Frame = { retAddr: number; baseSlot: number; fn: string; upvalues: Value[]; capabilities: Array<{cap: string; arg?: string}>; resourceLimits: {cpu?: number; memory?: number; io?: number}; opCount: number; ioCount: number };
    12→type TryHandler = { catchAddr: number; stackDepth: number; frameDepth: number };
    13→type LoopContext = {
    14→  addr: number;
    15→  iterationCount: number;
    16→  // Phase 3.8: State snapshot for memory isolation
    17→  stackHeightAtEntry: number;
    18→  globalSnapshotAtEntry: Map<string, Value>;
    19→  localSnapshotAtEntry: Value[];
    20→  stateChanges: { varName: string; before: Value; after: Value }[];
    21→};
    22→
    23→export class VM {
    24→  private stack: Value[] = [];
    25→  private globals = new Map<string, Value>();
    26→  private frames: Frame[] = [];
    27→  private tryStack: TryHandler[] = [];
    28→  private ip = 0;
    29→  private output: string[] = [];
    30→  private builtinFns: Record<string, BuiltinFn>;
    31→  // Phase 8: try/catch error handling
    32→  private lastError: Value | null = null;
    33→  private inTryCall = false;
    34→  // Phase 3.7: Safety guard & iteration tracking
    35→  // Phase 3.9: Jump Table & Offset Optimization
    36→  private jumpTable: JumpTable;
    37→  private offsetCalc: OffsetCalculator = new OffsetCalculator();
    38→  // Phase 5.9: Dynamic Memory Allocator
    39→  private memoryAllocator: MemoryAllocator = new MemoryAllocator();
    40→  // STEP 1: HeapManager (v6 재설계)
    41→  private heapManager: HeapManager = new HeapManager();
    42→  // Phase 4: Unsafe 격리 레이어
    43→  private unsafeManager: UnsafeManager = new UnsafeManager();
    44→  private currentUnsafeZone: number = -1;
    45→  private unsafeDepth: number = 0;
    46→
    47→  // Phase 6: Built-in capability requirements
    48→  private readonly BUILTIN_REQUIRED_CAPABILITIES = new Map<string, string>([
    49→    ["file_read", "read_file"],
    50→    ["file_write", "write_file"],
    51→    ["http_request", "network"],
    52→    ["http_get", "network"],
    53→    ["process_spawn", "spawn_process"],
    54→    ["eval", "execute_code"],
    55→  ]);
    56→
    57→  private traceMode = false;
    58→  private traceLogs: string[] = [];
    59→  private loopStack: LoopContext[] = [];  // Track loop start positions + iteration counts
    60→  private loopDepth = 0;                   // Track nesting depth
    61→  private readonly MAX_SAFE_ITERATIONS = 1_000_000;  // Safety guard limit
    62→
    63→  constructor(private chunk: Chunk, initialGlobals?: Map<string, Value>) {
    64→    this.builtinFns = getBuiltins();
    65→    this.jumpTable = new JumpTable(this.loopStack);
    66→
    67→    // Register builtins
    68→    for (const name of Object.keys(this.builtinFns)) {
    69→      this.globals.set(name, { tag: "builtin", name });
    70→    }
    71→    // Restore persisted globals (e.g. from REPL)
    72→    if (initialGlobals) {
    73→      for (const [k, v] of initialGlobals) {
    74→        if (!this.globals.has(k)) this.globals.set(k, v);
    75→      }
    76→    }
    77→
    78→    // PHASE 3: HeapManager에 Root Collector 콜백 등록
    79→    this.heapManager.setRootCollector(() => this.getRoots());
    80→  }
    81→
    82→  getGlobals(): Map<string, Value> { return new Map(this.globals); }
    83→
    84→  // Phase 6: Check if current function has required capability for builtin
    85→  // Phase 6.4: Extended to check path/network/resource limits
    86→  private checkBuiltinCapability(builtinName: string, args: Value[] = []): void {
    87→    const required = this.BUILTIN_REQUIRED_CAPABILITIES.get(builtinName);
    88→    if (!required) return; // Safe builtins (print, len, etc) pass through
    89→
    90→    const caps = this.getCurrentCapabilities();
    91→    const hasCapability = caps.some(c => c.cap === required);
    92→
    93→    if (!hasCapability) {
    94→      this.runtimeError(
    95→        `[CapabilityError] '${builtinName}' requires capability '${required}', ` +
    96→        `but current function does not declare it`
    97→      );
    98→    }
    99→
   100→    // Phase 6.4: Path/Network runtime validation
   101→    if (required === "read_file" || required === "write_file") {
   102→      const pathArg = args[0]?.tag === "str" ? args[0].val : null;
   103→      if (pathArg !== null && pathArg !== "") {
   104→        const allowedCaps = caps.filter(c => c.cap === required);
   105→        const allowed = allowedCaps.some(c => !c.arg || this.pathIsUnder(pathArg, c.arg));
   106→        if (!allowed) {
   107→          const allowedPaths = allowedCaps.map(c => c.arg ?? "*").join(", ");
   108→          this.runtimeError(
   109→            `[CapabilityError] Access to '${pathArg}' denied. ` +
   110→            `Allowed paths: [${allowedPaths}]`
   111→          );
   112→        }
   113→      }
   114→
   115→      // Phase 6.4: IO counter for resource limit
   116→      if (this.frames.length > 0) {
   117→        const frame = this.frames[this.frames.length - 1];
   118→        frame.ioCount++;
   119→        if (frame.resourceLimits.io && frame.ioCount > frame.resourceLimits.io) {
   120→          this.runtimeError(
   121→            `[ResourceLimitError] IO limit exceeded (${frame.resourceLimits.io} ops)`
   122→          );
   123→        }
   124→      }
   125→    }
   126→
   127→    if (required === "network") {
   128→      const urlArg = args[0]?.tag === "str" ? args[0].val : null;
   129→      if (urlArg !== null && urlArg !== "") {
   130→        const domain = this.extractDomain(urlArg);
   131→        const allowedCaps = caps.filter(c => c.cap === "network");
   132→        const allowed = allowedCaps.some(c => !c.arg || this.hostMatches(domain, c.arg));
   133→        if (!allowed) {
   134→          const allowedHosts = allowedCaps.map(c => c.arg ?? "*").join(", ");
   135→          this.runtimeError(
   136→            `[CapabilityError] Network access to '${domain}' denied. ` +
   137→            `Allowed hosts: [${allowedHosts}]`
   138→          );
   139→        }
   140→      }
   141→    }
   142→  }
   143→
   144→  // Phase 6.4: Path traversal check
   145→  private pathIsUnder(target: string, allowedPrefix: string): boolean {
   146→    if (target.includes("..")) return false;
   147→    const normalize = (p: string) => p.replace(/\/+/g, "/").replace(/\/$/, "");
   148→    const t = normalize(target);
   149→    const p = normalize(allowedPrefix);
   150→    return t === p || t.startsWith(p + "/");
   151→  }
   152→
   153→  // Phase 6.4: Extract domain from URL
   154→  private extractDomain(url: string): string {
   155→    try {
   156→      const match = url.match(/^(?:https?:\/\/)?([^\/\?#:]+)/);
   157→      return match ? match[1] : url;
   158→    } catch {
   159→      return url;
   160→    }
   161→  }
   162→
   163→  // Phase 6.4: Network host pattern matching
   164→  private hostMatches(target: string, pattern: string): boolean {
   165→    if (pattern === target) return true;
   166→    if (pattern.startsWith("*.")) {
   167→      const base = pattern.slice(2);
   168→      return target.endsWith("." + base) &&
   169→             !target.slice(0, -base.length - 1).includes(".");
   170→    }
   171→    return false;
   172→  }
   173→
   174→  // Phase 6: Get capabilities from current frame
   175→  private getCurrentCapabilities(): Array<{cap: string; arg?: string}> {
   176→    if (this.frames.length === 0) return [];
   177→    return this.frames[this.frames.length - 1].capabilities;
   178→  }
   179→
   180→  run(): { output: string[]; result: Value } {
   181→    while (this.ip < this.chunk.code.length) {
   182→      const op = this.chunk.code[this.ip++];
   183→      if (op === Op.Halt) {
   184→        return { output: this.output, result: this.stack.length > 0 ? this.peek() : { tag: "null" } };
   185→      }
   186→      try {
   187→        this.execOp(op);
   188→      } catch (e) {
   189→        // If error was caught by a try handler
   190→        if (e instanceof Error && e.message.startsWith("__FREELANG_ERROR_CAUGHT__")) {
   191→          // Continue from the new IP (which should point to catch handler or finally)
   192→          continue;
   193→        }
   194→        // Re-throw unhandled errors
   195→        throw e;
   196→      }
   197→    }
   198→    return { output: this.output, result: { tag: "null" } };
   199→  }
   200→
   201→  // Public API for builtins
   202→  getGlobal(name: string): Value | undefined { return this.globals.get(name); }
   203→  setGlobal(name: string, val: Value) { this.globals.set(name, val); }
   204→  getOutput(): string[] { return this.output; }
   205→  addOutput(s: string) { this.output.push(s); }
   206→  getLastError(): Value | null { return this.lastError; }
   207→  clearLastError() { this.lastError = null; }
   208→
   209→  // Phase 5.9: Memory Allocator API for builtins
   210→  getAllocator() { return this.memoryAllocator; }
   211→
   212→  // PHASE 3: GC Root Collection
   213→  /**
   214→   * Stack, Globals, Frames에서 모든 포인터 수집 (GC Root)
   215→   */
   216→  private getRoots(): number[] {
   217→    const roots: number[] = [];
   218→
   219→    // 1. Stack의 모든 포인터 수집
   220→    this.stack.forEach(val => {
   221→      if (val.tag === "ptr") {
   222→        roots.push(val.addr);
   223→      }
   224→    });
   225→
   226→    // 2. Globals의 모든 포인터 수집
   227→    this.globals.forEach(val => {
   228→      if (val.tag === "ptr") {
   229→        roots.push(val.addr);
   230→      }
   231→    });
   232→
   233→    // 3. Frames의 upvalues 포인터 수집
   234→    this.frames.forEach(frame => {
   235→      frame.upvalues.forEach(val => {
   236→        if (val.tag === "ptr") {
   237→          roots.push(val.addr);
   238→        }
   239→      });
   240→    });
   241→
   242→    return roots;
   243→  }
   244→
   245→  // Trace mode for PC debugging
   246→  enableTrace() { this.traceMode = true; this.traceLogs = []; }
   247→  getTraceLogs(): string[] { return this.traceLogs; }
   248→
   249→  /** Call a FreeLang fn or builtin Value from within a builtin (HOFs). */
   250→  callValue(callee: Value, args: Value[]): Value {
   251→    if (callee.tag === "builtin") {
   252→      return this.builtinFns[callee.name](args, this);
   253→    }
   254→    if (callee.tag === "fn") {
   255→      const savedIp = this.ip;
   256→      const targetFrameDepth = this.frames.length;
   257→
   258→      // Mimic Call opcode: push callee + args, push frame
   259→      this.stack.push(callee);
   260→      for (const a of args) this.stack.push(a);
   261→      this.frames.push({
   262→        retAddr: savedIp,
   263→        baseSlot: this.stack.length - args.length,
   264→        fn: callee.name,
   265→        upvalues: callee.freeVars,
   266→        capabilities: callee.capabilities || [],  // Phase 6: Pass capabilities
   267→        resourceLimits: (callee as any).resourceLimits || {},  // Phase 6.4
   268→        opCount: 0,  // Phase 6.4
   269→        ioCount: 0,  // Phase 6.4
   270→      });
   271→      this.ip = callee.addr;
   272→
   273→      // Execute until our frame is popped by Return
   274→      try {
   275→        while (this.frames.length > targetFrameDepth) {
   276→          const op = this.chunk.code[this.ip++];
   277→          this.execOp(op);
   278→        }
   279→      } catch (e) {
   280→        // Re-throw sentinel errors so try_call can catch them
   281→        if (e instanceof Error && e.message === "__FREELANG_ERROR_CAUGHT__") {
   282→          throw e;
   283→        }
   284→        // Re-throw other errors
   285→        throw e;
   286→      }
   287→      // Return handler pushed the result onto the stack and restored ip
   288→      return this.stack.pop()!;
   289→    }
   290→    throw new Error(`Cannot call ${callee.tag}`);
   291→  }
   292→
   293→  /** Safe call for try_call builtin - captures errors as Value objects */
   294→  trySafeCall(callee: Value, args: Value[]): { ok: boolean; value?: Value; error?: Value } {
   295→    this.clearLastError();
   296→    this.inTryCall = true;
   297→
   298→    try {
   299→      if (callee.tag === "builtin") {
   300→        const retVal = this.builtinFns[callee.name](args, this);
   301→        return { ok: true, value: retVal };
   302→      }
   303→      if (callee.tag === "fn") {
   304→        const retVal = this.callValue(callee, args);
   305→        return { ok: true, value: retVal };
   306→      }
   307→      return { ok: false, error: { tag: "str", val: `Cannot call ${callee.tag}` } };
   308→    } catch (e) {
   309→      // Check if a FreeLang error occurred
   310→      if (e instanceof Error && e.message.startsWith("__FREELANG_ERROR_CAUGHT__")) {
   311→        // Return the last error that was caught
   312→        return { ok: false, error: this.lastError || { tag: "str", val: "Unknown error" } };
   313→      }
   314→      // Otherwise return string error
   315→      return { ok: false, error: { tag: "str", val: String(e) } };
   316→    } finally {
   317→      this.inTryCall = false;
   318→    }
   319→  }
   320→
   321→  stringify(v: Value): string {
   322→    switch (v.tag) {
   323→      case "num": return String(v.val);
   324→      case "str": return v.val;
   325→      case "bool": return String(v.val);
   326→      case "null": return "null";
   327→      case "array": return "[" + v.val.map(e => this.stringify(e)).join(", ") + "]";
   328→      case "object": {
   329→        const entries = Array.from(v.val.entries()).map(([k, v2]) => `${k}: ${this.stringify(v2)}`);
   330→        return "{" + entries.join(", ") + "}";
   331→      }
   332→      case "fn": return `<fn ${v.name}>`;
   333→      case "builtin": return `<builtin ${v.name}>`;
   334→      default: return "<unknown>";
   335→    }
   336→  }
   337→
   338→  // --- Private internals ---
   339→
   340→  private execOp(op: number) {
   341→    // Phase 6.4: Resource limit checking (CPU + Memory)
   342→    if (this.frames.length > 0) {
   343→      const frame = this.frames[this.frames.length - 1];
   344→      frame.opCount++;
   345→
   346→      // CPU: opcode execution count limit
   347→      if (frame.resourceLimits.cpu && frame.opCount > frame.resourceLimits.cpu) {
   348→        this.runtimeError(
   349→          `[ResourceLimitError] CPU limit exceeded (${frame.resourceLimits.cpu} ops)`
   350→        );
   351→      }
   352→
   353→      // Memory: heap usage limit
   354→      if (frame.resourceLimits.memory) {
   355→        const heapUsed = this.heapManager.getStats().totalAllocated;
   356→        if (heapUsed > frame.resourceLimits.memory) {
   357→          this.runtimeError(
   358→            `[ResourceLimitError] Memory limit exceeded (${frame.resourceLimits.memory} slots)`
   359→          );
   360→        }
   361→      }
   362→    }
   363→
   364→    switch (op) {
   365→      case Op.Const: {
   366→        const value = this.chunk.constants[this.chunk.code[this.ip++]];
   367→        // STEP 1: HeapManager를 통한 할당 및 역참조
   368→        const heapPtr = this.valueToHeapPtr(value);
   369→        const dereferencedValue = this.heapPtrToValue(heapPtr);
   370→        this.stack.push(dereferencedValue);
   371→        break;
   372→      }
   373→      case Op.Pop: this.stack.pop(); break;
   374→      case Op.Dup: this.stack.push(this.peek()); break;
   375→
   376→      // Arithmetic
   377→      case Op.Add: {
   378→        const b = this.pop(), a = this.pop();
   379→        const result = this.add(a, b);
   380→        // STEP 3: 결과를 Heap에 할당하여 refCount 추적
   381→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   382→        break;
   383→      }
   384→      case Op.Sub: {
   385→        const b = this.popNum(), a = this.popNum();
   386→        const result = num(a - b);
   387→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   388→        break;
   389→      }
   390→      case Op.Mul: {
   391→        const b = this.popNum(), a = this.popNum();
   392→        const result = num(a * b);
   393→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   394→        break;
   395→      }
   396→      case Op.Div: {
   397→        const b = this.popNum(), a = this.popNum();
   398→        if (b === 0) this.runtimeError("Division by zero");
   399→        const result = num(a / b);
   400→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   401→        break;
   402→      }
   403→      case Op.Mod: {
   404→        const b = this.popNum(), a = this.popNum();
   405→        const result = num(a % b);
   406→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   407→        break;
   408→      }
   409→
   410→      // Phase 5.5: Typed Arithmetic Op (런타임 타입 체크 없음)
   411→      case Op.AddNum: {
   412→        const b = (this.pop() as any).val as number;
   413→        const a = (this.pop() as any).val as number;
   414→        const result = num(a + b);
   415→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   416→        break;
   417→      }
   418→      case Op.SubNum: {
   419→        const b = (this.pop() as any).val as number;
   420→        const a = (this.pop() as any).val as number;
   421→        const result = num(a - b);
   422→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   423→        break;
   424→      }
   425→      case Op.MulNum: {
   426→        const b = (this.pop() as any).val as number;
   427→        const a = (this.pop() as any).val as number;
   428→        const result = num(a * b);
   429→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   430→        break;
   431→      }
   432→      case Op.DivNum: {
   433→        const b = (this.pop() as any).val as number;
   434→        const a = (this.pop() as any).val as number;
   435→        if (b === 0) this.runtimeError("Division by zero");
   436→        const result = num(a / b);
   437→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   438→        break;
   439→      }
   440→      case Op.ModNum: {
   441→        const b = (this.pop() as any).val as number;
   442→        const a = (this.pop() as any).val as number;
   443→        const result = num(a % b);
   444→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   445→        break;
   446→      }
   447→      case Op.AddStr: {
   448→        const b = (this.pop() as any).val as string;
   449→        const a = (this.pop() as any).val as string;
   450→        const result = { tag: "str" as const, val: a + b };
   451→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   452→        break;
   453→      }
   454→      case Op.EqNum: {
   455→        const b = (this.pop() as any).val as number;
   456→        const a = (this.pop() as any).val as number;
   457→        const result = bool(a === b);
   458→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   459→        break;
   460→      }
   461→      case Op.LtNum: {
   462→        const b = (this.pop() as any).val as number;
   463→        const a = (this.pop() as any).val as number;
   464→        const result = bool(a < b);
   465→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   466→        break;
   467→      }
   468→      case Op.GtNum: {
   469→        const b = (this.pop() as any).val as number;
   470→        const a = (this.pop() as any).val as number;
   471→        const result = bool(a > b);
   472→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   473→        break;
   474→      }
   475→      case Op.LteNum: {
   476→        const b = (this.pop() as any).val as number;
   477→        const a = (this.pop() as any).val as number;
   478→        const result = bool(a <= b);
   479→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   480→        break;
   481→      }
   482→      case Op.GteNum: {
   483→        const b = (this.pop() as any).val as number;
   484→        const a = (this.pop() as any).val as number;
   485→        const result = bool(a >= b);
   486→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   487→        break;
   488→      }
   489→
   490→      case Op.Neg: {
   491→        const result = num(-this.popNum());
   492→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   493→        break;
   494→      }
   495→
   496→      // Comparison
   497→      case Op.Eq: {
   498→        const b = this.pop(), a = this.pop();
   499→        const result = bool(this.valEq(a, b));
   500→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   501→        break;
   502→      }
   503→      case Op.Neq: {
   504→        const b = this.pop(), a = this.pop();
   505→        const result = bool(!this.valEq(a, b));
   506→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   507→        break;
   508→      }
   509→      case Op.Lt: {
   510→        const b = this.popNum(), a = this.popNum();
   511→        const result = bool(a < b);
   512→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   513→        break;
   514→      }
   515→      case Op.Gt: {
   516→        const b = this.popNum(), a = this.popNum();
   517→        const result = bool(a > b);
   518→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   519→        break;
   520→      }
   521→      case Op.Lte: {
   522→        const b = this.popNum(), a = this.popNum();
   523→        const result = bool(a <= b);
   524→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   525→        break;
   526→      }
   527→      case Op.Gte: {
   528→        const b = this.popNum(), a = this.popNum();
   529→        const result = bool(a >= b);
   530→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   531→        break;
   532→      }
   533→
   534→      // Logic
   535→      case Op.And: {
   536→        const b = this.pop(), a = this.pop();
   537→        const result = bool(this.truthy(a) && this.truthy(b));
   538→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   539→        break;
   540→      }
   541→      case Op.Or: {
   542→        const b = this.pop(), a = this.pop();
   543→        const result = bool(this.truthy(a) || this.truthy(b));
   544→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   545→        break;
   546→      }
   547→      case Op.Not: {
   548→        const result = bool(!this.truthy(this.pop()));
   549→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   550→        break;
   551→      }
   552→
   553→      // Jump (v3.9: Optimized with Jump Table)
   554→      case Op.Jump: {
   555→        const targetAddr = this.chunk.code[this.ip];
   556→        const offset = this.offsetCalc.calculateOffset(this.ip, targetAddr);
