   558→        // Back jump = loop-back condition
   559→        if (offset < 0) {
   560→          // Find or create loop context (direct access for reliability)
   561→          let loopContext = this.loopStack.find(l => l.addr === targetAddr);
   562→
   563→          if (!loopContext) {
   564→            // First iteration: capture state snapshot for memory isolation check
   565→            const snapshot = this.captureSnapshot();
   566→            loopContext = {
   567→              addr: targetAddr,
   568→              iterationCount: 0,
   569→              stackHeightAtEntry: snapshot.stackHeight,
   570→              globalSnapshotAtEntry: snapshot.globals,
   571→              localSnapshotAtEntry: snapshot.locals,
   572→              stateChanges: [],
   573→            };
   574→            this.loopStack.push(loopContext);
   575→            this.loopDepth++;
   576→          }
   577→
   578→          // Increment iteration count
   579→          loopContext.iterationCount++;
   580→
   581→          // Safety guard: panic if exceeded
   582→          if (loopContext.iterationCount > this.MAX_SAFE_ITERATIONS) {
   583→            this.runtimeError(
   584→              `[PANIC] Safety guard triggered at loop PC ${loopContext.addr}. ` +
   585→              `Max iterations (${this.MAX_SAFE_ITERATIONS}) exceeded.`
   586→            );
   587→          }
   588→
   589→          if (this.traceMode) {
   590→            const indent = "  ".repeat(this.loopDepth);
   591→            this.traceLogs.push(
   592→              `${indent}[JUMP] PC: ${this.ip} → ${targetAddr} (loop-back, offset: ${offset}) | ` +
   593→              `Iteration: ${loopContext.iterationCount}/${this.MAX_SAFE_ITERATIONS}`
   594→            );
   595→          }
   596→        }
   597→
