   599→        break;
   600→      }
   601→      case Op.JumpIfFalse: {
   602→        const addr = this.chunk.code[this.ip++];
   603→        const cond = this.pop();
   604→        const indent = "  ".repeat(this.loopDepth);
   605→
   606→        if (!this.truthy(cond)) {
   607→          // Loop condition FALSE = exit loop
   608→          if (this.loopStack.length > 0) {
   609→            const loopContext = this.loopStack[this.loopStack.length - 1];
   610→
   611→            // Phase 3.8: Compare final state with entry snapshot
   612→            const finalSnapshot = this.captureSnapshot();
   613→            const comparison = this.compareSnapshots(
   614→              {
   615→                stackHeight: loopContext.stackHeightAtEntry,
   616→                globals: loopContext.globalSnapshotAtEntry,
   617→                locals: loopContext.localSnapshotAtEntry,
   618→              },
   619→              {
   620→                stackHeight: finalSnapshot.stackHeight,
   621→                globals: finalSnapshot.globals,
   622→                locals: finalSnapshot.locals,
   623→              }
   624→            );
