   626→            if (this.traceMode) {
   627→              this.traceLogs.push(
   628→                `${indent}[JUMPIF] PC: ${this.ip-1} → ${addr} (condition FALSE, exit loop) | ` +
   629→                `Final iteration count: ${loopContext.iterationCount}`
   630→              );
