   632→                `${indent}  └─ Stack balanced: ${comparison.stackBalanced} | ` +
   633→                `Global changes: ${comparison.globalChanges.length} | ` +
   634→                `Local corruption: ${comparison.localChanges}`
   635→              );
   636→              for (const [varName, before, after] of comparison.globalChanges) {
   637→                this.traceLogs.push(
   638→                  `${indent}     ├─ ${varName}: ${this.stringify(before)} → ${this.stringify(after)}`
   639→                );
   640→              }
   641→            }
   642→
   643→            // Store state changes for later analysis
   644→            loopContext.stateChanges = comparison.globalChanges.map(([name, before, after]) => ({
   645→              varName: name,
   646→              before,
   647→              after,
   648→            }));
   649→
   650→            this.loopStack.pop();
   651→            this.loopDepth--;
   652→            if (this.traceMode) {
   653→              this.traceLogs.push(`${indent}  └─ Loop depth: ${this.loopDepth}`);
   654→            }
   655→          }
   656→          this.ip = addr;
   657→        } else {
   658→          // Loop condition TRUE = continue looping
   659→          if (this.traceMode) {
   660→            this.traceLogs.push(`${indent}[JUMPIF] PC: ${this.ip-1} (condition TRUE, continue loop)`);
   661→          }
   662→        }
   663→        break;
   664→      }
   665→      case Op.JumpIfTrue: { const addr = this.chunk.code[this.ip++]; if (this.truthy(this.pop())) this.ip = addr; break; }
   666→
   667→      // Variables
   668→      case Op.Load: {
   669→        const slot = this.chunk.code[this.ip++];
   670→        const value = this.stack[this.baseSlot() + slot];
   671→        // STEP 4: 지역 변수를 Heap 기반으로 로드
   672→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(value)));
   673→        break;
   674→      }
   675→      case Op.Store: {
   676→        const slot = this.chunk.code[this.ip++];
   677→        const value = this.peek();
   678→        // STEP 4: 지역 변수를 Heap에 할당하여 저장
   679→        this.stack[this.baseSlot() + slot] = this.heapPtrToValue(this.valueToHeapPtr(value));
   680→        break;
   681→      }
   682→      case Op.LoadGlobal: {
   683→        const name = this.chunk.constants[this.chunk.code[this.ip++]] as { tag: "str"; val: string };
   684→        const val = this.globals.get(name.val);
   685→        if (val === undefined) this.runtimeError(`Undefined variable '${name.val}'`);
   686→        // STEP 2: HeapManager 통합 - 글로벌 변수는 heap 기반으로 관리됨
   687→        // PHASE 3 수정: 포인터면 역참조하여 실제 값으로 반환
   688→        // 단, iterator는 상태 유지가 필요하므로 포인터 역참조 대상에서 제외
