   690→        break;
   691→      }
   692→      case Op.StoreGlobal: {
   693→        const name = this.chunk.constants[this.chunk.code[this.ip++]] as { tag: "str"; val: string };
   694→        const value = this.pop();
   695→        // STEP 2: HeapManager 통합 - 글로벌 변수를 heap에 할당
   696→        // PHASE 3 수정: 포인터를 globals에 직접 저장하여 GC root로 추적 가능하게
   697→        // 단, iterator는 상태 변화가 필요하므로 포인터로 변환하지 않음
   698→        if (value.tag === "iter") {
   699→          this.globals.set(name.val, value);
   700→        } else {
   701→          const heapPtr = this.valueToHeapPtr(value);
   702→          this.globals.set(name.val, heapPtr);
   703→        }
   704→        break;
   705→      }
   706→
   707→      // Functions
   708→      case Op.Call: {
   709→        const argc = this.chunk.code[this.ip++];
   710→        const callee = this.stack[this.stack.length - 1 - argc];
   711→        if (callee.tag === "fn") {
