   715→            retAddr: this.ip,
   716→            baseSlot: this.stack.length - argc,
   717→            fn: callee.name,
   718→            upvalues: callee.freeVars,
   719→            capabilities: callee.capabilities || [],
   720→            resourceLimits: (callee as any).resourceLimits || {},
