   822→        if (obj.tag === "object") {
   823→          const prop = obj.val.get(name.val) ?? { tag: "null" };
   824→          // STEP 5: 속성값도 Heap 기반으로
   825→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(prop)));
