   827→          const lengthVal = num(obj.val.length);
   828→          // STEP 5: length 속성도 Heap 기반으로
   829→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(lengthVal)));
   830→        } else if (obj.tag === "str" && name.val === "length") {
   831→          const lengthVal = num(obj.val.length);
   832→          // STEP 5: length 속성도 Heap 기반으로
   833→          this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(lengthVal)));
   834→        } else {
   835→          this.stack.push({ tag: "null" });
   836→        }
   837→        break;
   838→      }
   839→      case Op.SetProp: {
   840→        const propName = this.pop();
   841→        const obj = this.pop();
   842→        const val = this.peek();
   843→        if (obj.tag === "object" && propName.tag === "str") {
   844→          // STEP 5: 설정되는 속성값도 Heap에 할당
   845→          const heapVal = this.heapPtrToValue(this.valueToHeapPtr(val));
   846→          obj.val.set(propName.val, heapVal);
   847→        }
   848→        break;
   849→      }
   850→
   851→      // Closures
   852→      case Op.NewClosure: {
   853→        const numFree = this.chunk.code[this.ip++];
   854→        const fnVal = this.pop();
   855→        if (fnVal.tag !== "fn") this.runtimeError("NewClosure expects fn");
   856→        const freeVars: Value[] = new Array(numFree);
   857→        for (let i = numFree - 1; i >= 0; i--) freeVars[i] = this.pop();
