   860→      }
   861→      case Op.LoadFree: {
   862→        const idx = this.chunk.code[this.ip++];
   863→        const frame = this.frames[this.frames.length - 1];
   864→        this.stack.push(frame.upvalues[idx]);
   865→        break;
   866→      }
   867→      case Op.StoreFree: {
   868→        const idx = this.chunk.code[this.ip++];
   869→        const frame = this.frames[this.frames.length - 1];
   870→        frame.upvalues[idx] = this.peek();
   871→        break;
   872→      }
   873→
   874→      // Print
   875→      case Op.Print: this.output.push(this.stringify(this.pop())); break;
   876→      case Op.Println: this.output.push(this.stringify(this.pop()) + "\n"); break;
