   883→      }
   884→      case Op.TryEnd: this.tryStack.pop(); break;
   885→      case Op.Throw: {
   886→        const err = this.pop();
   887→        this.handleError(err);
   888→        break;
   889→      }
   890→
   891→      // Iterator
   892→      case Op.Iter: {
   893→        const val = this.pop();
