   898→      }
   899→      case Op.IterNext: {
   900→        const iter = this.pop();
   901→        if (iter.tag === "iter") {
   902→          this.stack.push(iter.val[iter.idx] ?? { tag: "null" });
   903→          iter.idx++;
   904→        } else {
   905→          this.stack.push({ tag: "null" });
   906→        }
   907→        break;
   908→      }
   909→      case Op.IterDone: {
   910→        const iter = this.pop();
   911→        this.stack.push(bool(iter.tag === "iter" && iter.idx >= iter.val.length));
