   919→        // For simplicity, we use a numeric ID as the address
   920→        const ptrAddr = this.memoryAllocator.allocate(JSON.stringify(val).length);
   921→        if (ptrAddr > 0) {
   922→          this.stack.push({ tag: "ptr", addr: ptrAddr, target: val });
   923→        } else {
   924→          this.runtimeError("Cannot allocate memory for pointer");
   925→        }
   926→        break;
   927→      }
   928→      case Op.Deref: {
   929→        const ptr = this.pop();
