   932→          if (ptr.target) {
   933→            this.stack.push(ptr.target);
   934→          } else {
   935→            this.runtimeError(`Null pointer dereference`);
   936→          }
   937→        } else {
   938→          this.runtimeError(`Cannot dereference non-pointer type ${ptr.tag}`);
   939→        }
   940→        break;
   941→      }
   942→
   943→      // Phase 4: Unsafe 격리 레이어
   944→      case Op.UnsafeBegin: {
   945→        this.unsafeDepth++;
