  1005→        if (newSizeVal.tag !== "num") {
  1006→          this.runtimeError("realloc size must be number");
  1007→        }
  1008→        if (ptrVal.tag !== "num") {
  1009→          this.runtimeError("realloc requires pointer");
  1010→        }
  1011→
  1012→        const zoneId = Math.floor(ptrVal.val);
  1013→        const newSize = Math.floor(newSizeVal.val);
  1014→        const result = this.unsafeManager.realloc(zoneId, newSize);
