  1100→  // Phase 3.8: Memory snapshot for state integrity
  1101→  private captureSnapshot(): { stackHeight: number; globals: Map<string, Value>; locals: Value[] } {
  1102→    const stackHeight = this.stack.length;
  1103→    const globals = new Map(this.globals);
