  1108→  private compareSnapshots(
  1109→    before: { stackHeight: number; globals: Map<string, Value>; locals: Value[] },
  1110→    after: { stackHeight: number; globals: Map<string, Value>; locals: Value[] }
  1111→  ): { stackBalanced: boolean; globalChanges: [string, Value, Value][]; localChanges: boolean } {
  1112→    const stackBalanced = before.stackHeight === after.stackHeight;
  1113→
  1114→    // Find global changes
  1115→    const globalChanges: [string, Value, Value][] = [];
  1116→    for (const [key, beforeVal] of before.globals) {
  1117→      const afterVal = after.globals.get(key);
  1118→      if (!this.valEq(beforeVal, afterVal || { tag: "null" })) {
  1119→        globalChanges.push([key, beforeVal, afterVal || { tag: "null" }]);
