  1191→        break;
  1192→      case "str":
  1193→        typeId = TYPE_ID.STR;
  1194→        payload = value.val;
  1195→        break;
  1196→      case "bool":
  1197→        typeId = TYPE_ID.BOOL;
  1198→        payload = value.val;
  1199→        break;
  1200→      case "null":
  1201→        typeId = TYPE_ID.NULL;
  1202→        payload = null;
  1203→        break;
  1204→      case "array":
  1205→        typeId = TYPE_ID.ARRAY;
  1206→        payload = value.val;
  1207→        break;
  1208→      case "object":
  1209→        typeId = TYPE_ID.OBJECT;
  1210→        payload = value.val;
  1211→        break;
  1212→      case "fn":
  1213→        typeId = TYPE_ID.FN;
  1214→        payload = value;
  1215→        break;
  1216→      case "builtin":
  1217→        typeId = TYPE_ID.BUILTIN;
  1218→        payload = value.name;
  1219→        break;
  1220→      case "iter":
