  1236→  /**
  1237→   * STEP 1: Ptr Value에서 실제 값으로 역참조
  1238→   */
  1239→  private heapPtrToValue(ptrValue: Value): Value {
  1240→    if (ptrValue.tag !== "ptr") {
  1241→      // 이미 실제 값이면 그대로 반환
  1242→      return ptrValue;
  1243→    }
  1244→
  1245→    const ptr = ptrValue.addr;
  1246→    const heapObj = this.heapManager.get(ptr);
  1247→    if (!heapObj) {
