  1249→    }
  1250→
  1251→    // HeapObject를 Value로 변환
  1252→    const typeId = heapObj!.typeId;
  1253→    const payload = heapObj!.payload;
  1254→
  1255→    switch (typeId) {
  1256→      case TYPE_ID.NUM:
  1257→        return { tag: "num", val: payload };
  1258→      case TYPE_ID.STR:
  1259→        return { tag: "str", val: payload };
  1260→      case TYPE_ID.BOOL:
  1261→        return { tag: "bool", val: payload };
  1262→      case TYPE_ID.NULL:
  1263→        return { tag: "null" };
  1264→      case TYPE_ID.ARRAY:
  1265→        return { tag: "array", val: payload };
  1266→      case TYPE_ID.OBJECT:
  1267→        return { tag: "object", val: payload };
  1268→      case TYPE_ID.FN:
  1269→        return payload as Value; // 이미 fn 형식
  1270→      case TYPE_ID.BUILTIN:
  1271→        return { tag: "builtin", name: payload };
  1272→      case TYPE_ID.ITER:
  1273→        return { tag: "iter", val: payload, idx: 0 };
