  1276→    }
  1277→  }
  1278→
  1279→  private runtimeError(msg: string): never {
  1280→    const err: Value = { tag: "str", val: msg };
  1281→    if (this.tryStack.length > 0) {
  1282→      this.handleError(err);
  1283→      // Throw sentinel that run() loop will catch and handle
  1284→      throw new Error("__FREELANG_ERROR_CAUGHT__");
  1285→    }
  1286→    throw new Error(`Runtime Error: ${msg}`);
  1287→  }
  1288→
  1289→  /**
  1290→   * STEP 1: HeapManager 접근 (테스트용)
  1291→   */
  1292→  public getHeapManager(): HeapManager {
  1293→    return this.heapManager;
  1294→  }
  1295→
  1296→  /**
  1297→   * Phase 4: UnsafeManager 접근 (테스트용)
  1298→   */
  1299→  public getUnsafeManager(): UnsafeManager {
  1300→    return this.unsafeManager;
  1301→  }
  1302→}
