   421→  function compileFnBody(name: string, params: Param[], body: Stmt[], annotations: any[] = []) {
   422→    // Phase 6: Extract capabilities from allow-kind annotations
   423→    const capabilities = annotations
   424→      .filter((a: any) => a.kind === "allow")
   425→      .map((a: any) => ({ cap: a.cap, arg: a.arg }));
   426→
   427→    // Phase 6.4: Extract resource limits from limit-kind annotations
   428→    const resourceLimits: Record<string, number> = {};
   429→    annotations
   430→      .filter((a: any) => a.kind === "limit")
   431→      .forEach((a: any) => {
   432→        resourceLimits[a.resource] = a.value;
   433→      });
   434→
   435→    const jumpOver = currentPos(); emitArg(Op.Jump, 0);
   436→    const fnAddr = currentPos();
   437→    scopes.push({ locals: [], depth: 1, upvalues: [] });
   438→    for (const p of params) declareLocal(p.name);  // Phase 5.5.3: .name 추출
   439→    // Compile body as expression: last stmt should leave value on stack
   440→    if (body.length === 0) {
   441→      emitArg(Op.Const, addConst({ tag: "null" }));
   442→    } else {
   443→      compileStmtsAsExpr(body);
   444→    }
   445→    emit(Op.Return);
   446→    const fnScope = scopes.pop()!;
   447→    patchJump(jumpOver);
   448→
   449→    if (fnScope.upvalues.length > 0) {
   450→      for (const uv of fnScope.upvalues) {
   451→        if (uv.isLocal) emitArg(Op.Load, uv.index);
   452→        else emitArg(Op.LoadFree, uv.index);
   453→      }
   454→      emitArg(Op.Const, addConst({ tag: "fn", name, arity: params.length, addr: fnAddr, freeVars: [], capabilities, resourceLimits }));
   455→      emitArg(Op.NewClosure, fnScope.upvalues.length);
   456→    } else {
   457→      emitArg(Op.Const, addConst({ tag: "fn", name, arity: params.length, addr: fnAddr, freeVars: [], capabilities, resourceLimits }));
   458→    }
   459→  }
