   461→  function compileExpr(e: Expr) {
   462→    switch (e.kind) {
   463→      case "number": emitArg(Op.Const, addConst({ tag: "num", val: e.value })); break;
   464→      case "string": emitArg(Op.Const, addConst({ tag: "str", val: e.value })); break;
   465→      case "bool": emitArg(Op.Const, addConst({ tag: "bool", val: e.value })); break;
   466→      case "null": emitArg(Op.Const, addConst({ tag: "null" })); break;
   467→      case "ident": {
   468→        const local = resolveLocal(e.name);
   469→        if (local !== -1) { emitArg(Op.Load, local); break; }
   470→        const upval = resolveUpvalue(e.name);
   471→        if (upval !== -1) { emitArg(Op.LoadFree, upval); break; }
   472→        emitArg(Op.LoadGlobal, addConst({ tag: "str", val: e.name }));
   473→        break;
   474→      }
   475→      case "binary": {
   476→        // Phase 5.4: 상수 폴딩 - 숫자 + 숫자 연산
   477→        if (e.left.kind === "number" && e.right.kind === "number") {
   478→          const l = e.left.value, r = e.right.value;
   479→          let result: Value | null = null;
   480→          if (e.op === "+") result = { tag: "num", val: l + r };
   481→          else if (e.op === "-") result = { tag: "num", val: l - r };
   482→          else if (e.op === "*") result = { tag: "num", val: l * r };
   483→          else if (e.op === "/" && r !== 0) result = { tag: "num", val: l / r };
   484→          else if (e.op === "%") result = { tag: "num", val: l % r };
   485→          else if (e.op === "==") result = { tag: "bool", val: l === r };
   486→          else if (e.op === "!=") result = { tag: "bool", val: l !== r };
   487→          else if (e.op === "<") result = { tag: "bool", val: l < r };
   488→          else if (e.op === ">") result = { tag: "bool", val: l > r };
   489→          else if (e.op === "<=") result = { tag: "bool", val: l <= r };
   490→          else if (e.op === ">=") result = { tag: "bool", val: l >= r };
   491→          if (result) { emitArg(Op.Const, addConst(result)); break; }
