   500→        compileExpr(e.left);
   501→        compileExpr(e.right);
   502→
   503→        // Phase 5.5: Typed Op 선택
   504→        const leftType = inferExprType(e.left);
   505→        const rightType = inferExprType(e.right);
   506→
   507→        // num + num → Typed Arithmetic
   508→        if (leftType === "num" && rightType === "num") {
   509→          const typedArith: Record<string, Op> = {
   510→            "+": Op.AddNum, "-": Op.SubNum, "*": Op.MulNum,
   511→            "/": Op.DivNum, "%": Op.ModNum,
   512→            "==": Op.EqNum, "<": Op.LtNum, ">": Op.GtNum,
   513→            "<=": Op.LteNum, ">=": Op.GteNum,
   514→          };
   515→          if (typedArith[e.op] !== undefined) { emit(typedArith[e.op]); break; }
   516→        }
   517→
   518→        // str + str → AddStr
   519→        if (leftType === "str" && rightType === "str" && e.op === "+") {
   520→          emit(Op.AddStr); break;
   521→        }
   522→
   523→        // Generic fallback
   524→        const ops: Record<string, Op> = {
   525→          "+": Op.Add, "-": Op.Sub, "*": Op.Mul, "/": Op.Div, "%": Op.Mod,
   526→          "==": Op.Eq, "!=": Op.Neq, "<": Op.Lt, ">": Op.Gt, "<=": Op.Lte, ">=": Op.Gte,
   527→          "&&": Op.And, "||": Op.Or,
   528→        };
