   542→        for (const arg of e.args) compileExpr(arg);
   543→        emitArg(Op.Call, e.args.length);
   544→        break;
   545→      }
   546→      case "assign": {
   547→        compileExpr(e.value);
   548→        if (e.target.kind === "ident") {
   549→          const local = resolveLocal(e.target.name);
