   551→          else {
   552→            const upval = resolveUpvalue(e.target.name);
   553→            if (upval !== -1) { emit(Op.Dup); emitArg(Op.StoreFree, upval); }
   554→            else { emit(Op.Dup); emitArg(Op.StoreGlobal, addConst({ tag: "str", val: e.target.name })); }
   555→          }
   556→        } else if (e.target.kind === "index") {
   557→          compileExpr(e.target.object);
   558→          compileExpr(e.target.index);
   559→          emit(Op.SetIndex);
   560→        } else if (e.target.kind === "member") {
   561→          compileExpr(e.target.object);
   562→          emitArg(Op.Const, addConst({ tag: "str", val: e.target.property }));
   563→          emit(Op.SetProp);
   564→        }
   565→        break;
   566→      }
   567→      case "array": {
   568→        for (const el of e.elements) compileExpr(el);
   569→        emitArg(Op.NewArray, e.elements.length);
   570→        break;
   571→      }
   572→      case "object": {
   573→        for (const { key, value } of e.entries) {
   574→          emitArg(Op.Const, addConst({ tag: "str", val: key }));
   575→          compileExpr(value);
   576→        }
   577→        emitArg(Op.NewObject, e.entries.length);
   578→        break;
   579→      }
   580→      case "index": {
   581→        compileExpr(e.object);
   582→        compileExpr(e.index);
   583→        emit(Op.Index);
   584→        break;
   585→      }
   586→      case "member": {
