   599→        const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   600→        patchJump(jumpFalse);
   601→        compileExpr(e.else);
   602→        patchJump(jumpEnd);
   603→        break;
   604→      }
   605→      case "if": {
