   615→        break;
   616→      }
   617→      case "match": {
   618→        // Match expression: evaluate subject and match against patterns
   619→        compileExpr(e.subject);
   620→        const tempName = `__match_${currentPos()}`;
   621→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: tempName }));
   622→
   623→        const endPatches: number[] = [];
   624→        for (const arm of e.arms) {
   625→          if (arm.pattern !== null) {
   626→            // Load subject for comparison
   627→            emitArg(Op.LoadGlobal, addConst({ tag: "str", val: tempName }));
