     1→// Jump Table Optimization Module
     2→// Purpose: Fast lookup and caching of jump offsets and loop contexts
     3→
     4→export class JumpTable {
     5→  private addrToLoopIdx: Map<number, number> = new Map();
     6→  private lastLookedupAddr: number = -1;
     7→  private lastLookedupIdx: number = -1;
     8→
     9→  constructor(private loopContexts: any[]) {}
    10→
    11→  /**
    12→   * Fast lookup of loop context by address with caching
    13→   * O(1) on cache hit, O(n) only on cache miss
    14→   */
    15→  findLoopByAddr(addr: number): { idx: number; context: any } | null {
    16→    // Cache hit
    17→    if (addr === this.lastLookedupAddr) {
    18→      const idx = this.lastLookedupIdx;
    19→      return idx >= 0 ? { idx, context: this.loopContexts[idx] } : null;
    20→    }
    21→
    22→    // Check map cache
    23→    if (this.addrToLoopIdx.has(addr)) {
    24→      const idx = this.addrToLoopIdx.get(addr)!;
    25→      this.lastLookedupAddr = addr;
    26→      this.lastLookedupIdx = idx;
    27→      return { idx, context: this.loopContexts[idx] };
    28→    }
    29→
    30→    // Linear search (only on first miss)
    31→    for (let i = 0; i < this.loopContexts.length; i++) {
    32→      if (this.loopContexts[i].addr === addr) {
    33→        this.addrToLoopIdx.set(addr, i);
    34→        this.lastLookedupAddr = addr;
    35→        this.lastLookedupIdx = i;
    36→        return { idx: i, context: this.loopContexts[i] };
    37→      }
    38→    }
    39→
    40→    // Not found
    41→    this.lastLookedupAddr = addr;
    42→    this.lastLookedupIdx = -1;
    43→    return null;
    44→  }
    45→
    46→  /**
    47→   * Get the most recent loop context (top of stack)
    48→   */
    49→  getTopLoop(): { idx: number; context: any } | null {
    50→    if (this.loopContexts.length === 0) return null;
    51→    const idx = this.loopContexts.length - 1;
    52→    return { idx, context: this.loopContexts[idx] };
    53→  }
    54→
    55→  /**
    56→   * Invalidate cache when stack changes
    57→   */
    58→  invalidateCache() {
    59→    this.addrToLoopIdx.clear();
    60→    this.lastLookedupAddr = -1;
    61→    this.lastLookedupIdx = -1;
    62→  }
    63→
    64→  /**
    65→   * Check if address is a known loop start
    66→   */
    67→  isLoopAddr(addr: number): boolean {
    68→    return this.addrToLoopIdx.has(addr) ||
    69→           this.loopContexts.some(ctx => ctx.addr === addr);
    70→  }
    71→}
    72→
    73→/**
    74→ * Offset calculation helper - pre-compute jump offsets
    75→ */
    76→export class OffsetCalculator {
    77→  private offsetCache: Map<number, number> = new Map();
    78→
    79→  /**
    80→   * Calculate forward offset (positive = forward, negative = backward)
    81→   */
    82→  calculateOffset(from: number, to: number): number {
    83→    const key = (from << 16) | (to & 0xFFFF); // Combine two 16-bit values
    84→    if (this.offsetCache.has(key)) {
    85→      return this.offsetCache.get(key)!;
    86→    }
    87→    const offset = to - from;
    88→    this.offsetCache.set(key, offset);
    89→    return offset;
    90→  }
    91→
    92→  /**
    93→   * Classify jump type
    94→   */
    95→  classifyJump(offset: number): 'loop-back' | 'forward-exit' | 'local' {
    96→    if (offset < 0) return 'loop-back';
    97→    if (offset > 100) return 'forward-exit'; // Arbitrary threshold
    98→    return 'local';
    99→  }
   100→
   101→  clearCache() {
   102→    this.offsetCache.clear();
   103→  }
   104→}
