    42→export interface AllocationError {
    43→  type: "double_free" | "use_after_free" | "invalid_address" | "null_pointer";
    44→  addr: number;
    45→  message: string;
    46→}
    47→
    48→export interface LeakInfo {
    49→  blockId: number;
    50→  size: number;
    51→  addr: number;
    52→  allocatedAt: number;
    53→  sourceFile?: string;
    54→  sourceLine?: number;
    55→  sourceInfo?: string;
