    70→  message: string;
    71→  timestamp: number;
    72→}
    73→
    74→export class MemoryAllocator {
    75→  private blocks: Map<number, MemoryBlock> = new Map();
    76→  private addrToId: Map<number, number> = new Map(); // Quick lookup: addr -> id
    77→  private nextAddr: number = 100000; // Start allocation at 100000
    78→  private nextId: number = 1;
    79→  private freeList: MemoryBlock[] = []; // List of freed blocks for reuse
    80→  private errors: AllocationError[] = []; // Track errors
    81→
    82→  // v5.9.6: Pool management for small object optimization
    83→  private static readonly POOL_SIZES = [8, 16, 32, 64, 128] as const;
    84→  private static readonly POOL_THRESHOLD = 128;
    85→  private pools: Map<number, MemoryBlock[]> = new Map();
    86→  private poolHits: number = 0;
    87→  private poolMisses: number = 0;
    88→
    89→  // v5.9.7: Heap corruption detection (Canary values)
