    96→  private danglingPointerViolations: DanglingPointerViolation[] = [];
    97→  private freedAddresses: Set<number> = new Set(); // Track freed addresses
    98→  private allocatedAddresses: Set<number> = new Set(); // Track currently allocated addresses
    99→
   100→  // v5.9.9: Call Frame tracking for recursion & context isolation
