   107→  static readonly MAX_RECURSION_DEPTH = 1000;
   108→  private recursionPanics: RecursionPanic[] = [];
   109→
   110→  constructor() {
   111→    // Initialize pool buckets for each pool size
   112→    for (const size of MemoryAllocator.POOL_SIZES) {
   113→      this.pools.set(size, []);
   114→    }
