   253→      // Clear source info after use
   254→      this.nextSourceFile = undefined;
   255→      this.nextSourceLine = undefined;
   256→
   257→      this.blocks.set(used.id, used);
   258→      this.addrToId.set(used.addr, used.id);
   259→
   260→      // v5.9.8: Track allocated address and remove from freed set
   261→      this.allocatedAddresses.add(used.addr);
   262→      this.freedAddresses.delete(used.addr);
   263→
   264→      // If there's a remainder, add it to free list
   265→      if (split.remainder) {
