   267→        split.remainder.canaryBefore = MemoryAllocator.CANARY_VALUE;
   268→        split.remainder.canaryAfter = MemoryAllocator.CANARY_VALUE;
   269→        this.blocks.set(split.remainder.id, split.remainder);
   270→        this.freeList.push(split.remainder);
   271→      }
   272→
   273→      // v5.9.9: Frame tracking
   274→      const currentFrameId1 = this.frameStack.at(-1);
   275→      if (currentFrameId1 !== undefined) {
   276→        used.frameId = currentFrameId1;
   277→        used.frameDepth = this.frameStack.length - 1;
   278→        this.frames.get(currentFrameId1)?.allocations.add(used.addr);
   279→      }
   280→
   281→      return used.addr;
   282→    }
   283→
   284→    // Allocate new block
   285→    const id = this.nextId++;
   286→    const addr = this.alignAddress(this.nextAddr);
   287→
   288→    const block: MemoryBlock = {
   289→      id,
   290→      size,
   291→      addr,
   292→      freed: false,
   293→      allocatedAt: Date.now(),
   294→      accessCount: 0,
   295→      sourceFile: this.nextSourceFile,
   296→      sourceLine: this.nextSourceLine,
   297→      sourceInfo: this.nextSourceFile && this.nextSourceLine
   298→        ? `${this.nextSourceFile}:${this.nextSourceLine}`
   299→        : undefined,
   300→      // v5.9.7: Canary values for corruption detection
   301→      canaryBefore: MemoryAllocator.CANARY_VALUE,
   302→      canaryAfter: MemoryAllocator.CANARY_VALUE,
   303→    };
   304→
   305→    // Clear source info after use
   306→    this.nextSourceFile = undefined;
   307→    this.nextSourceLine = undefined;
   308→
   309→    this.blocks.set(id, block);
   310→    this.addrToId.set(addr, id);
   311→    this.nextAddr = addr + Math.max(size, 8);
   312→
   313→    // v5.9.8: Track allocated address
   314→    this.allocatedAddresses.add(addr);
   315→    this.freedAddresses.delete(addr);
   316→
   317→    // v5.9.9: Frame tracking
   318→    const currentFrameId2 = this.frameStack.at(-1);
   319→    if (currentFrameId2 !== undefined) {
   320→      block.frameId = currentFrameId2;
   321→      block.frameDepth = this.frameStack.length - 1;
   322→      this.frames.get(currentFrameId2)?.allocations.add(addr);
   323→    }
   324→
   325→    return addr;
   326→  }
