   328→  /**
   329→   * Free memory at given pointer
   330→   * Detects double-free errors and triggers coalescing (v5.9.4)
   331→   * v5.9.6: Pool blocks return to pool instead of freeList
   332→   * v5.9.7: Verify canary before freeing
   333→   */
   334→  free(addr: number): boolean {
   335→    if (addr === 0) {
   336→      this.recordError("null_pointer", addr, "Cannot free NULL pointer");
   337→      return false;
   338→    }
   339→
   340→    const id = this.addrToId.get(addr);
   341→    if (!id) {
   342→      this.recordError("invalid_address", addr, `Invalid address: ${addr}`);
   343→      return false;
   344→    }
   345→
   346→    const block = this.blocks.get(id);
   347→    if (!block) {
   348→      this.recordError("invalid_address", addr, `Block not found for address: ${addr}`);
   349→      return false;
   350→    }
   351→
   352→    if (block.freed) {
   353→      this.recordError("double_free", addr, `Double-free detected at address: ${addr}`);
   354→      return false;
   355→    }
   356→
   357→    // v5.9.7: Check for heap corruption before freeing
   358→    this.verifyCanary(addr);
   359→    if (this.corruptionDetected) {
   360→      this.recordError("invalid_address", addr, `Heap corruption detected at address: ${addr}`);
   361→      return false;
   362→    }
   363→
   364→    // v5.9.8: Mark address as freed (dangling pointer prevention)
   365→    this.freedAddresses.add(addr);
   366→    this.allocatedAddresses.delete(addr);
   367→
   368→    // v5.9.9: Remove from frame tracking
   369→    if (block.frameId !== undefined) {
   370→      this.frames.get(block.frameId)?.allocations.delete(addr);
   371→    }
   372→
   373→    // v5.9.6: Pool path - return to pool
   374→    if (block.isPoolBlock && block.poolSize) {
   375→      block.freed = true;
   376→      block.freedAt = Date.now();
   377→      // v5.9.8: Zap pool block data
   378→      block.canaryBefore = MemoryAllocator.ZAPPED_MARKER;
   379→      block.canaryAfter = MemoryAllocator.ZAPPED_MARKER;
   380→      const pool = this.pools.get(block.poolSize)!;
   381→      pool.push(block);
   382→      return true;
   383→    }
   384→
   385→    // Heap path - return to freeList with coalescing
   386→    block.freed = true;
   387→    block.freedAt = Date.now();
   388→    // v5.9.8: Zap heap block data
   389→    block.canaryBefore = MemoryAllocator.ZAPPED_MARKER;
   390→    block.canaryAfter = MemoryAllocator.ZAPPED_MARKER;
   391→    this.freeList.push(block);
   392→
   393→    // v5.9.4: Trigger coalescing to reduce fragmentation
   394→    this.coalesceBlocks();
   395→
   396→    return true;
   397→  }
