   399→  /**
   400→   * Access memory (simulated)
   401→   * Detects use-after-free errors
   402→   * v5.9.8: Dangling pointer detection
   403→   */
   404→  access(addr: number): boolean {
   405→    if (addr === 0) {
   406→      this.recordError("null_pointer", addr, "Cannot access NULL pointer");
   407→      return false;
   408→    }
   409→
   410→    // v5.9.8: Check if address is in freed set (dangling pointer)
   411→    if (this.freedAddresses.has(addr)) {
   412→      this.recordDanglingPointerViolation(addr, "access", "Dangling pointer access detected");
   413→      this.recordError("use_after_free", addr, `Dangling pointer at address: ${addr}`);
   414→      return false;
   415→    }
   416→
   417→    // v5.9.8: Check if address is currently allocated
   418→    if (!this.allocatedAddresses.has(addr)) {
   419→      this.recordDanglingPointerViolation(addr, "access", "Address not allocated");
   420→      this.recordError("invalid_address", addr, `Invalid address: ${addr}`);
   421→      return false;
   422→    }
   423→
   424→    const id = this.addrToId.get(addr);
   425→    if (!id) {
   426→      this.recordError("invalid_address", addr, `Invalid address: ${addr}`);
   427→      return false;
   428→    }
   429→
   430→    const block = this.blocks.get(id);
   431→    if (!block) {
   432→      this.recordError("invalid_address", addr, `Block not found for address: ${addr}`);
   433→      return false;
   434→    }
   435→
   436→    if (block.freed) {
   437→      this.recordError("use_after_free", addr, `Use-after-free at address: ${addr} (freed at ${block.freedAt})`);
   438→      return false;
   439→    }
