   466→  /**
   467→   * Find best-fit freed block (v5.9.4: Fragmentation Prevention)
   468→   * Searches for the smallest block that fits the requested size
   469→   */
   470→  private findBestFitBlock(size: number): MemoryBlock | undefined {
   471→    let best: MemoryBlock | undefined = undefined;
   472→    let bestFit = Infinity;
   473→
   474→    for (const block of this.freeList) {
   475→      if (block.size >= size && block.size < bestFit) {
   476→        best = block;
   477→        bestFit = block.size;
   478→      }
   479→    }
   480→
   481→    if (best) {
   482→      this.freeList = this.freeList.filter(b => b !== best);
   483→    }
   484→
   485→    return best;
   486→  }
