   488→  /**
   489→   * Coalesce adjacent free blocks (v5.9.4)
   490→   * Merges neighboring freed blocks to reduce fragmentation
   491→   */
   492→  private coalesceBlocks(): void {
   493→    if (this.freeList.length < 2) return;
   494→
   495→    // Sort free list by address for coalescing
   496→    const sorted = [...this.freeList].sort((a, b) => a.addr - b.addr);
   497→
   498→    const merged: MemoryBlock[] = [];
   499→    let current = sorted[0];
   500→
   501→    for (let i = 1; i < sorted.length; i++) {
   502→      const next = sorted[i];
   503→      const currentEnd = current.addr + current.size;
   504→
   505→      // Check if blocks are adjacent (or overlapping, which shouldn't happen)
   506→      if (currentEnd === next.addr) {
   507→        // Merge blocks
   508→        current = {
   509→          ...current,
   510→          size: current.size + next.size,
   511→        };
   512→      } else {
   513→        // Not adjacent, keep current and start new
   514→        merged.push(current);
   515→        current = next;
   516→      }
   517→    }
   518→
   519→    merged.push(current);
   520→    this.freeList = merged;
   521→  }
