   523→  /**
   524→   * Split a large block if needed (v5.9.4)
   525→   * When allocating from a larger block, keep the remainder if it's large enough
   526→   */
   527→  private splitBlock(
   528→    block: MemoryBlock,
   529→    requestedSize: number
   530→  ): { used: MemoryBlock; remainder?: MemoryBlock } {
   531→    const MIN_SPLIT_SIZE = 4; // Minimum fragment size to keep
   532→    const remainingSize = block.size - requestedSize;
   533→
   534→    const used: MemoryBlock = {
   535→      ...block,
   536→      size: requestedSize,
   537→    };
   538→
   539→    if (remainingSize >= MIN_SPLIT_SIZE) {
   540→      const remainder: MemoryBlock = {
   541→        id: this.nextId++,
   542→        size: remainingSize,
   543→        addr: block.addr + requestedSize,
   544→        freed: true,
   545→        allocatedAt: Date.now(),
   546→        accessCount: 0,
   547→      };
   548→      return { used, remainder };
   549→    }
   550→
   551→    return { used };
   552→  }
   553→
   554→  /**
   555→   * Calculate fragmentation ratio (0-100%) (v5.9.4)
   556→   */
   557→  getFragmentationRatio(): number {
   558→    if (this.freeList.length === 0) return 0;
   559→
   560→    const totalFree = this.freeList.reduce((sum, b) => sum + b.size, 0);
   561→    const largestFree = Math.max(...this.freeList.map(b => b.size));
   562→
   563→    if (totalFree === 0) return 0;
   564→
   565→    // Fragmentation = (total free - largest free) / total free * 100
   566→    // 0% = perfectly coalesced, 100% = completely fragmented
   567→    return Math.round(((totalFree - largestFree) / totalFree) * 100);
   568→  }
   569→
   570→  /**
   571→   * Get fragmentation statistics (v5.9.4)
   572→   */
   573→  getFragmentationStats(): {
   574→    totalFree: number;
   575→    largestFree: number;
   576→    numFragments: number;
   577→    ratio: number;
   578→  } {
   579→    const totalFree = this.freeList.reduce((sum, b) => sum + b.size, 0);
   580→    const largestFree =
   581→      this.freeList.length > 0 ? Math.max(...this.freeList.map(b => b.size)) : 0;
   582→
   583→    return {
   584→      totalFree,
   585→      largestFree,
   586→      numFragments: this.freeList.length,
   587→      ratio: this.getFragmentationRatio(),
   588→    };
   589→  }
