   591→  /**
   592→   * Align address to 4-byte boundary (v5.9.2: Data Alignment)
   593→   */
   594→  private alignAddress(addr: number): number {
   595→    const alignment = 4;
   596→    const remainder = addr % alignment;
   597→    return remainder === 0 ? addr : addr + (alignment - remainder);
   598→  }
   599→
   600→  /**
   601→   * Get alignment requirement for a type (v5.9.2)
   602→   */
   603→  static getTypeAlignment(type: string): number {
   604→    const t = type.toLowerCase().trim();
   605→    const alignMap: Record<string, number> = {
   606→      "i32": 4,
   607→      "i64": 8,
   608→      "f32": 4,
   609→      "f64": 8,
   610→      "bool": 1,
   611→      "byte": 1,
   612→      "char": 1,
   613→      "string": 4,  // Pointer-like
   614→      "any": 4,
   615→      "ptr": 4,     // Pointer type
   616→      "null": 1,
   617→    };
   618→    return alignMap[t] || 4;
   619→  }
   620→
   621→  /**
   622→   * Calculate aligned offset (v5.9.2)
   623→   * Aligns offset to the required boundary before adding field
   624→   */
   625→  static calculateAlignedOffset(currentOffset: number, fieldAlignment: number): number {
   626→    if (fieldAlignment <= 1) return currentOffset;
   627→    const remainder = currentOffset % fieldAlignment;
   628→    return remainder === 0 ? currentOffset : currentOffset + (fieldAlignment - remainder);
   629→  }
   630→
   631→  /**
   632→   * Calculate padding needed (v5.9.2)
   633→   */
   634→  static calculatePadding(currentOffset: number, fieldAlignment: number): number {
   635→    const alignedOffset = this.calculateAlignedOffset(currentOffset, fieldAlignment);
   636→    return alignedOffset - currentOffset;
   637→  }
