   660→  /**
   661→   * Get memory stats
   662→   */
   663→  getStats() {
   664→    const allocated = Array.from(this.blocks.values()).filter(b => !b.freed);
   665→    const freed = Array.from(this.blocks.values()).filter(b => b.freed);
   666→    const totalAllocated = allocated.reduce((sum, b) => sum + b.size, 0);
   667→    const totalFreed = freed.reduce((sum, b) => sum + b.size, 0);
   668→
   669→    return {
   670→      allocatedBlocks: allocated.length,
   671→      freedBlocks: freed.length,
