   686→  /**
   687→   * Generate detailed leak report (v5.9.5)
   688→   * Includes block ID, size, address, allocation time, and source info
   689→   */
   690→  generateLeakReport(): LeakReport {
   691→    const leaked = this.detectLeaks();
   692→    const now = Date.now();
   693→
   694→    const leaks: LeakInfo[] = leaked.map(block => ({
   695→      blockId: block.id,
   696→      size: block.size,
   697→      addr: block.addr,
   698→      allocatedAt: block.allocatedAt,
   699→      sourceFile: block.sourceFile,
   700→      sourceLine: block.sourceLine,
   701→      sourceInfo: block.sourceInfo,
   702→      ageMs: now - block.allocatedAt
   703→    }));
   704→
   705→    return {
   706→      totalLeaked: leaked.reduce((sum, b) => sum + b.size, 0),
   707→      leakCount: leaked.length,
   708→      leaks,
   709→      timestamp: now
   710→    };
   711→  }
