   713→  /**
   714→   * Format leak report as human-readable string
   715→   */
   716→  formatLeakReport(): string {
   717→    const report = this.generateLeakReport();
   718→    const lines: string[] = [];
   719→
   720→    lines.push("╔════════════════════════════════════════════════════════╗");
   721→    lines.push("║        🔴 MEMORY LEAK REPORT (v5.9.5 Leak Guard)     ║");
   722→    lines.push("╚════════════════════════════════════════════════════════╝");
   723→    lines.push("");
   724→
   725→    if (report.leakCount === 0) {
   726→      lines.push("✅ No memory leaks detected! Clean heap.");
   727→      lines.push(`   Total Allocated: ${report.totalLeaked} bytes`);
   728→      return lines.join("\n");
   729→    }
   730→
   731→    lines.push(`❌ LEAK DETECTED: ${report.leakCount} block(s), ${report.totalLeaked} bytes`);
   732→    lines.push("");
   733→
   734→    for (const leak of report.leaks) {
   735→      lines.push(`Block #${leak.blockId}:`);
   736→      lines.push(`  Address: 0x${leak.addr.toString(16)}`);
   737→      lines.push(`  Size: ${leak.size} bytes`);
   738→      lines.push(`  Allocated at: ${new Date(leak.allocatedAt).toISOString()}`);
   739→      lines.push(`  Age: ${leak.ageMs}ms`);
   740→
   741→      if (leak.sourceFile || leak.sourceLine) {
   742→        lines.push(`  Source: ${leak.sourceFile}:${leak.sourceLine}`);
   743→      }
   744→      if (leak.sourceInfo) {
   745→        lines.push(`  Info: ${leak.sourceInfo}`);
   746→      }
   747→
   748→      lines.push("");
   749→    }
   750→
   751→    lines.push(`Total Leaked: ${report.totalLeaked} bytes`);
   752→    lines.push(`Fragmentation Ratio: ${this.getFragmentationRatio()}%`);
   753→
   754→    return lines.join("\n");
   755→  }
