   829→  /**
   830→   * v5.9.7: Verify canary values for a block
   831→   * Returns true if canary is intact, false if corrupted
   832→   */
   833→  private verifyCanary(addr: number): boolean {
   834→    const id = this.addrToId.get(addr);
   835→    if (!id) return true; // Not tracked, assume safe
   836→
   837→    const block = this.blocks.get(id);
   838→    if (!block) return true;
   839→
   840→    const before = block.canaryBefore;
   841→    const after = block.canaryAfter;
   842→
   843→    if (before !== MemoryAllocator.CANARY_VALUE || after !== MemoryAllocator.CANARY_VALUE) {
   844→      this.corruptionDetected = true;
   845→      if (!this.corruptedBlocks.includes(id)) {
   846→        this.corruptedBlocks.push(id);
   847→      }
   848→      return false;
   849→    }
   850→
   851→    return true;
   852→  }
   853→
   854→  /**
   855→   * v5.9.7: Check heap invariants (full integrity scan)
   856→   * Returns true if heap structure is valid
   857→   */
   858→  checkHeapInvariants(): boolean {
   859→    // Check 1: All allocated blocks have valid canary
   860→    for (const [, block] of this.blocks) {
   861→      if (!block.freed) {
   862→        if (!this.verifyCanary(block.addr)) {
   863→          return false;
   864→        }
   865→      }
   866→    }
   867→
   868→    // Check 2: Free list pointers are all valid
   869→    for (const freeBlock of this.freeList) {
   870→      if (!this.blocks.has(freeBlock.id)) {
   871→        return false;
   872→      }
   873→    }
   874→
   875→    // Check 3: Pool blocks are consistent
   876→    for (const [size, pool] of this.pools) {
   877→      for (const block of pool) {
   878→        if (!this.blocks.has(block.id)) {
   879→          return false;
   880→        }
   881→        if (block.poolSize !== size) {
   882→          return false;
