    27→/**
    28→ * 타입 ID 상수
    29→ */
    30→export const TYPE_ID = {
    31→  NUM: 1,
    32→  STR: 2,
    33→  BOOL: 3,
    34→  NULL: 4,
    35→  ARRAY: 5,
    36→  OBJECT: 6,
    37→  FN: 7,
    38→  BUILTIN: 8,
    39→  ITER: 9,
    40→  PTR: 10,
    41→} as const;
    42→
    43→/**
    44→ * HeapManager: 모든 메모리 할당/해제 관리
    45→ */
    46→export class HeapManager {
