    85→    const obj: HeapObject = {
    86→      id,
    87→      typeId,
    88→      refCount: 1,
    89→      gcMark: false,
    90→      flags: 0,
    91→      payload,
    92→      createdAt: Date.now(),
    93→    };
    94→
    95→    this.objects.set(id, obj);
    96→    this.stats.totalAllocated++;
    97→    this.stats.currentObjects++;
    98→
    99→    return id;
   100→  }
   101→
   102→  /**
   103→   * HeapObject 접근
   104→   */
   105→  public get(ptr: number): HeapObject | null {
   106→    const obj = this.objects.get(ptr);
   107→    if (!obj) {
   108→      console.error(`[HeapManager] Invalid pointer: ${ptr}`);
   109→      return null;
   110→    }
   111→    return obj;
   112→  }
   113→
   114→  /**
   115→   * HeapObject 수정 (업데이트)
   116→   */
   117→  public set(ptr: number, obj: Partial<HeapObject>): void {
   118→    const existing = this.objects.get(ptr);
   119→    if (!existing) {
   120→      console.error(`[HeapManager] Invalid pointer for set: ${ptr}`);
   121→      return;
   122→    }
   123→
