   125→  }
   126→
   127→  /**
   128→   * 메모리 해제
   129→   */
   130→  public free(ptr: number): void {
   131→    const obj = this.objects.get(ptr);
   132→    if (!obj) {
   133→      console.error(`[HeapManager] Free on invalid pointer: ${ptr}`);
   134→      return;
   135→    }
   136→
   137→    this.objects.delete(ptr);
   138→    this.stats.totalFreed++;
   139→    this.stats.currentObjects--;
   140→  }
   141→
   142→  /**
   143→   * 참조 계수 증가
   144→   */
   145→  public incrementRefCount(ptr: number): void {
