   176→  }
   177→
   178→  /**
   179→   * 포인터 유효성 확인
   180→   */
   181→  public isValid(ptr: number): boolean {
   182→    return this.objects.has(ptr);
   183→  }
   184→
   185→  /**
   186→   * GC 마크 설정
   187→   */
   188→  public setGCMark(ptr: number, mark: boolean): void {
   189→    const obj = this.objects.get(ptr);
   190→    if (obj) {
   191→      obj.gcMark = mark;
   192→    }
   193→  }
   194→
   195→  /**
   196→   * 통계
   197→   */
   198→  public getStats(): {
   199→    totalAllocated: number;
   200→    totalFreed: number;
   201→    currentObjects: number;
   202→    peakObjects: number;
   203→  } {
