   205→      ...this.stats,
   206→      peakObjects: this.stats.totalAllocated - this.stats.totalFreed,
   207→    };
   208→  }
   209→
   210→  /**
   211→   * 디버그: 모든 객체 출력
   212→   */
   213→  public debugDump(): void {
   214→    console.log(`[HeapManager] ${this.stats.currentObjects} objects alive`);
