   227→  public checkLeaks(): { leakedCount: number; totalSize: number } {
   228→    let leakedCount = 0;
   229→    let totalSize = 0;
   230→
   231→    this.objects.forEach(obj => {
   232→      if (obj.refCount > 0) {
   233→        leakedCount++;
   234→        const type = this.typeTable.get(obj.typeId);
   235→        totalSize += type?.size || 0;
   236→      }
   237→    });
   238→
