   241→
   242→  /**
   243→   * 모든 객체 명시적 해제 (테스트용)
   244→   */
   245→  public clear(): void {
   246→    this.objects.clear();
   247→    this.stats = {
   248→      totalAllocated: 0,
   249→      totalFreed: 0,
