   259→      obj.gcMark = false;
   260→    });
   261→  }
   262→
   263→  /**
   264→   * PHASE 3 GC: Root로부터 도달 가능한 객체들을 마크 (DFS)
   265→   */
   266→  private mark(ptr: number, visited: Set<number>): void {
   267→    // 이미 방문했으면 스킵 (순환 참조 방지)
   268→    if (visited.has(ptr)) {
   269→      return;
   270→    }
   271→
   272→    const obj = this.objects.get(ptr);
   273→    if (!obj) {
   274→      return;
   275→    }
   276→
   277→    visited.add(ptr);
   278→    obj.gcMark = true;
   279→
   280→    // 배열 요소들 순회
   281→    if (obj.typeId === TYPE_ID.ARRAY && Array.isArray(obj.payload)) {
   282→      obj.payload.forEach((element: any) => {
   283→        if (element && typeof element === 'object' && 'addr' in element) {
   284→          this.mark(element.addr, visited);
   285→        }
   286→      });
   287→    }
   288→
   289→    // 객체 속성들 순회
   290→    if (obj.typeId === TYPE_ID.OBJECT && obj.payload instanceof Map) {
   291→      obj.payload.forEach((value: any) => {
   292→        if (value && typeof value === 'object' && 'addr' in value) {
   293→          this.mark(value.addr, visited);
   294→        }
   295→      });
   296→    }
   297→
   298→    // 함수의 free 변수 (클로저) 순회
   299→    if (obj.typeId === TYPE_ID.FN && Array.isArray(obj.payload.freeVars)) {
   300→      obj.payload.freeVars.forEach((freeVar: any) => {
   301→        if (freeVar && typeof freeVar === 'object' && 'addr' in freeVar) {
   302→          this.mark(freeVar.addr, visited);
   303→        }
   304→      });
   305→    }
   306→  }
