   308→  /**
   309→   * PHASE 3 GC: 마크되지 않은 객체들 해제
   310→   */
   311→  private sweep(): void {
   312→    const toDelete: number[] = [];
   313→
   314→    this.objects.forEach((obj, ptr) => {
   315→      if (!obj.gcMark) {
   316→        toDelete.push(ptr);
   317→      }
   318→    });
   319→
   320→    toDelete.forEach(ptr => {
   321→      this.objects.delete(ptr);
   322→      this.stats.totalFreed++;
   323→      this.stats.currentObjects--;
   324→    });
   325→  }
   326→
   327→  /**
   328→   * PHASE 3 GC: Root 포인터들 수집 (VM이 제공하는 콜백)
   329→   * VM은 Stack, Globals, Frames의 모든 포인터를 반환해야 함
   330→   */
   331→  public setRootCollector(collector: () => number[]): void {
   332→    this.rootCollector = collector;
   333→  }
   334→
   335→  private rootCollector: (() => number[]) | null = null;
   336→
   337→  /**
   338→   * PHASE 3 GC: Root 포인터들 수집
   339→   */
   340→  private collectRoots(): number[] {
   341→    if (this.rootCollector) {
   342→      return this.rootCollector();
   343→    }
   344→    return [];
   345→  }
   346→
   347→  /**
   348→   * PHASE 3 GC: 강제 GC 실행 (Mark-Sweep)
   349→   */
   350→  public forceGC(): { markedCount: number; sweptCount: number } {
   351→    const beforeCount = this.stats.currentObjects;
   352→
   353→    // 1. 모든 gcMark 리셋
   354→    this.resetGCMarks();
   355→
   356→    // 2. Root로부터 도달 가능한 모든 객체 마크
   357→    const roots = this.collectRoots();
   358→    const visited = new Set<number>();
   359→    roots.forEach(ptr => {
   360→      this.mark(ptr, visited);
   361→    });
   362→
   363→    const markedCount = visited.size;
   364→
   365→    // 3. 마크되지 않은 객체들 해제
   366→    this.sweep();
   367→
   368→    const sweptCount = beforeCount - this.stats.currentObjects;
   369→
   370→    return { markedCount, sweptCount };
   371→  }
   372→
   373→  /**
   374→   * 순환 참조 감지 (디버그용)
   375→   */
   376→  public detectCycle(ptr: number): boolean {
   377→    const visited = new Set<number>();
   378→    const recStack = new Set<number>();
   379→
   380→    const hasCycle = (p: number): boolean => {
   381→      if (recStack.has(p)) {
   382→        return true; // 순환 발견
   383→      }
   384→      if (visited.has(p)) {
   385→        return false;
   386→      }
   387→
   388→      visited.add(p);
   389→      recStack.add(p);
   390→
   391→      const obj = this.objects.get(p);
   392→      if (!obj) return false;
   393→
   394→      // 배열 요소 확인
   395→      if (obj.typeId === TYPE_ID.ARRAY && Array.isArray(obj.payload)) {
   396→        for (const element of obj.payload) {
   397→          if (element && typeof element === 'object' && 'addr' in element) {
   398→            if (hasCycle(element.addr)) {
   399→              return true;
   400→            }
   401→          }
   402→        }
   403→      }
   404→
   405→      // 객체 속성 확인
   406→      if (obj.typeId === TYPE_ID.OBJECT && obj.payload instanceof Map) {
   407→        for (const value of obj.payload.values()) {
   408→          if (value && typeof value === 'object' && 'addr' in value) {
   409→            if (hasCycle(value.addr)) {
   410→              return true;
   411→            }
   412→          }
   413→        }
   414→      }
   415→
   416→      recStack.delete(p);
   417→      return false;
   418→    };
   419→
   420→    return hasCycle(ptr);
   421→  }
   422→}
